mapper.select:
SELECT psar.sku_id FROM app.product_sku ps LEFT JOIN app.product_sku_attribute_relation psar ON ps.id = psar.sku_id WHERE ps.product_id = #{productId} AND (psar.attribute_id, psar.attribute_value_id) IN
(#{item.attributeId}, #{item.attributeValueId})
GROUP BY psar.sku_id HAVING COUNT(*) = #{count}
